+        ];
+        canonicalize_map(&mut entries, 0).unwrap();
+        // Both same length → lexicographic order: 0xAA before 0xBB.
+        assert_eq!(entries[0].0, Value::Bytes(vec![0xAA]));
+        assert_eq!(entries[1].0, Value::Bytes(vec![0xBB]));
+    }
